<template>
  <v-container>
    <v-layout justify-center row wrap>
      <v-flex md10>
        <div>
          <v-form ref="form" v-model="valid" @submit.prevent="update">
            <v-text-field
              v-model="team[0].id"
              label="ID"
              prepend-icon="vpn_key"
              disabled
            />
            <v-text-field
              v-model="team[0].name"
              label="Name"
              :counter="30"
              :rules="nameRules"
              prepend-icon="person"
              required
            />
            <v-text-field
              v-model="team[0].email"
              label="Email"
              :rules="emailRules"
              prepend-icon="email"
              required
            />
            <v-text-field
              v-model="team[0].position"
              label="Position"
              :rules="[v => !!v || 'Position is required']"
              prepend-icon="stars"
              required
            />
            <v-text-field
              v-model="team[0].skills"
              label="Skills"
              :rules="[v => !!v || 'Skills is required']"
              prepend-icon="view_list"
              required
            />
            <v-btn :disabled="!valid" type="submit" small color="primary">
              Update
            </v-btn>
          </v-form>
        </div>
      </v-flex>
    </v-layout>
  </v-container>
</template>

<script>
export default {
  data() {
    return {
      teams: this.$store.state.teams,
      valid: true,
      nameRules: [
        v => !!v || "Name is required",
        v => (v && v.length <= 30) || "Name must be less than 10 characters"
      ],
      emailRules: [
        v => !!v || "E-mail is required",
        v => /.+@.+/.test(v) || "E-mail must be valid"
      ]
    };
  },
  computed: {
    team() {
      return this.teams.filter(team => {
        return team.id == this.$route.params.id;
      });
      // return this.$store.commit("team", this.$route.params.id);
    }
  },
  methods: {
    update() {
      this.$store.commit("update", this.team[0]);
      this.$router.push("/crud");
    }
  }
};
</script>

